#include <iostream>
#include <cmath>
#include <iomanip>

struct Point {
    int x, y;
};

extern double calculateDistance(Point p1, Point p2);

int main() {
    std::cout << std::fixed << std::setprecision(10);
    Point p1_test, p2_test;

    p1_test = {0, 0}; p2_test = {3, 4};
    std::cout << calculateDistance(p1_test, p2_test) << std::endl;

    p1_test = {1, 1}; p2_test = {1, 1};
    std::cout << calculateDistance(p1_test, p2_test) << std::endl;

    p1_test = {-1, -1}; p2_test = {1, 1};
    std::cout << calculateDistance(p1_test, p2_test) << std::endl;

    p1_test = {0, 0}; p2_test = {5, 12};
    std::cout << calculateDistance(p1_test, p2_test) << std::endl;

    p1_test = {10, 20}; p2_test = {13, 24};
    std::cout << calculateDistance(p1_test, p2_test) << std::endl;

    return 0;
}
